class Main {
  public static void main(String[] args) {
    String[] backpack = {"Sword", "Shield", "Potion"};
    System.out.println("Before: " + backpack[0]);

    // Throw out the sword, put a Bow in slot 0
    backpack[0] = "Bow";

    System.out.println("After: " + backpack[0]);
  }
}
